
const API_BASE = import.meta.env.VITE_API_BASE || "http://localhost:3001/api";

async function api(path, options = {}) {
  const res = await fetch(`${API_BASE}${path}`, {
    headers: options.body instanceof FormData ? undefined : { "Content-Type": "application/json" },
    ...options
  });
  if (!res.ok) {
    const text = await res.text();
    throw new Error(text || `${res.status} ${res.statusText}`);
  }
  return res.json();
}

export const getBackendHealth = () => api("/health");
export const getDashboardSummary = () => api("/dashboard/summary");

export const createTicket = (payload) => api("/tickets", { method: "POST", body: JSON.stringify(payload) });
export const getOutcomes = () => api("/outcomes");
export const createOutcome = (payload) => api("/outcomes", { method: "POST", body: JSON.stringify(payload) });
export const deleteOutcome = (id) => api(`/outcomes/${id}`, { method: "DELETE" });
export const getSimilarTickets = (q) => api(`/similar?q=${encodeURIComponent(q || "")}`);
export const searchReferences = (q) => api(`/references/search?q=${encodeURIComponent(q || "")}`);
export const trackOutcomeUsage = (id, payload) => api(`/outcomes/${id}/usage`, { method: "POST", body: JSON.stringify(payload) });

export const previewConsensus = (payload) => api("/consensus/preview", { method: "POST", body: JSON.stringify(payload) });
export const saveConsensusDecision = (payload) => api("/consensus/save", { method: "POST", body: JSON.stringify(payload) });
export const getConsensusHistory = () => api("/consensus/history");

export const saveApprovalLog = (payload) => api("/approvals", { method: "POST", body: JSON.stringify(payload) });
export const getApprovalHistory = () => api("/approvals");

export const previewRunbook = (payload) => api("/runbooks/preview", { method: "POST", body: JSON.stringify(payload) });
export const executeRunbook = (payload) => api("/runbooks/execute", { method: "POST", body: JSON.stringify(payload) });
export const evaluateRunbookSafety = (payload) => api("/runbooks/safety", { method: "POST", body: JSON.stringify(payload) });

export const saveExecutionLog = (payload) => api("/executions", { method: "POST", body: JSON.stringify(payload) });
export const getExecutionHistory = () => api("/executions");
export const clearExecutionHistory = () => api("/executions", { method: "DELETE" });

export const uploadKnowledgeDocument = ({ file, title, tags }) => {
  const fd = new FormData();
  if (file) fd.append("file", file);
  fd.append("title", title || "");
  fd.append("tags", tags || "");
  return api("/knowledge/upload", { method: "POST", body: fd });
};
export const searchKnowledge = (q) => api(`/knowledge/search?q=${encodeURIComponent(q || "")}`);
export const analyzeScreenshot = ({ file }) => {
  const fd = new FormData();
  if (file) fd.append("file", file);
  return api("/screenshots/analyze", { method: "POST", body: fd });
};
